# -*- coding: utf-8 -*-
from typing import List
class Solution:
    def heightOfTree(self, tree: List[int], n: int, root: int) -> int:
        if root >= n or root < 0:
            return 0
        if tree[root] == -1:
            return 0
        left_height = self.heightOfTree(tree, n, root * 2 + 1)
        right_height = self.heightOfTree(tree, n, root * 2 + 2)
        return 1 + max(left_height, right_height)
# Driver code
if __name__ == '__main__':
    sol = Solution()
    tree = [1,2,-1,-1,3]
    n = len(tree)
    root = 0
    print(sol.heightOfTree(tree, n, root))

