// -*- coding: utf-8;-*
#include <iostream>
using namespace std;
class Solution {
public:
    int heightOfTree(int* tree, int n, int root)
    {
        if (root >= n || root < 0)
            return 0;
        if (tree[root] == -1)
            return 0;
        int left_height = heightOfTree(tree, n, root * 2 + 1);
        int right_height = heightOfTree(tree, n, root * 2 + 2);
        return 1 + max(left_height, right_height);
    }
};
int main()
{
    Solution sol;
    int tree[] = {1,2,-1,-1,3};
    int n = sizeof(tree) / sizeof(tree[0]);
    int root = 0;
    cout << sol.heightOfTree(tree, n, root) << endl;
    return 0;
}
